      out.write("				\r\n");
      out.write("					var img = document.createElement(\"img\");\r\n");
      out.write("					img.src = \"./resources/upload/notice/\" + item.image\r\n");
      out.write("					\r\n");
      out.write("					anchor.appendChild(img)\r\n");
      out.write("					swiperSlidePopupWrap.appendChild(anchor)\r\n");
      out.write("					swiperSlide.appendChild(swiperSlidePopupWrap)\r\n");
      out.write("					swiperWrapper.appendChild(swiperSlide)\r\n");
      out.write("				}\r\n");
      out.write("				\r\n");
      out.write("				const popupSwiper = new Swiper(\".popupSwiper\", {\r\n");
      out.write("				    loop: true,\r\n");
      out.write("				    autoplay: {\r\n");
      out.write("				      delay: 3000,\r\n");
      out.write("				    },\r\n");
      out.write("				  });\r\n");
      out.write("				\r\n");
      out.write("			},\r\n");
      out.write("			error(err) {\r\n");
      out.write("				console.log(err)\r\n");
      out.write("			}\r\n");
      out.write("		})\r\n");
      out.write("		\r\n");
      out.write("		\r\n");
      out.write("\r\n");
      out.write("		closeBtn.addEventListener(\"click\", function(){\r\n");
